INSTRUCTION_GENERATION_TEMPLATE = """
Come up with a series of tasks. Each task consists of an instruction, \
an optional input, and an output. Here are some examples:

{examples}

Now generate a new task (number {next_num}):
Task {next_num}:
"""

def format_task(task: dict, num: int) -> str:
    parts = [f"Task {num}:", f"Instruction: {task['instruction']}"]
    if task.get('input'):
        parts.append(f"Input: {task['input']}")
    parts.append(f"Output: {task['output']}")
    return "\n".join(parts)


def build_instruction_prompt(sampled_tasks: list[dict]) -> str:
    examples = "\n\n".join(
        format_task(task, i+1) for i, task in enumerate(sampled_tasks)
    )
    return INSTRUCTION_GENERATION_TEMPLATE.format(
        examples=examples,
        next_num=len(sampled_tasks) + 1
    )

IS_CLASSIFICATION_PROMPT = """
Does the following task require the model to choose from a fixed set of labels?
Answer Yes or No.

Task: {instruction}

Answer:"""

def classify_task(instruction: str, llm_generate_fn) -> bool:
    """Returns True if the task is a classification task."""
    prompt = IS_CLASSIFICATION_PROMPT.format(instruction=instruction)
    response = llm_generate_fn(prompt, max_tokens=5).strip().lower()
    return response.startswith('yes')
